import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{n as i,r as a,t as o}from"./chunks/vm-arguments.BmU0TYdw.js";const s=JSON.parse(`{"title":"Launching the Game in IntelliJ IDEA","description":"Learn how to utilize the various launch profiles to start and debug your mods in a live game environment through IntelliJ IDEA.","frontmatter":{"title":"Launching the Game in IntelliJ IDEA","description":"Learn how to utilize the various launch profiles to start and debug your mods in a live game environment through IntelliJ IDEA.","authors":["IMB11","Tenneb22"],"prev":{"text":"Opening a Project in IntelliJ IDEA","link":"./opening-a-project"},"next":{"text":"Generating Sources in IntelliJ IDEA","link":"./generating-sources"},"files":[]},"headers":[],"relativePath":"develop/getting-started/intellij-idea/launching-the-game.md","filePath":"develop/getting-started/intellij-idea/launching-the-game.md","lastUpdated":1768343532000}`);var c={name:`develop/getting-started/intellij-idea/launching-the-game.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Launching the Game in IntelliJ IDEA <a class="header-anchor" href="#h1" aria-label="Permalink to “Launching the Game in IntelliJ IDEA”">​</a></h1><p>Fabric Loom provides a variety of launch profiles to help you start and debug your mods in a live game environment. This guide will cover the various launch profiles and how to use them to debug and playtest your mods.</p><h2 id="launch-profiles" tabindex="-1">Launch Profiles <a class="header-anchor" href="#launch-profiles" aria-label="Permalink to “Launch Profiles”">​</a></h2><p>If you&#39;re using IntelliJ IDEA, you can find the launch profiles in the top-right corner of the window. Click the dropdown menu to see the available launch profiles.</p><p>There should be a client and server profile, with the option to either run it normally or in debug mode:</p><p><img src="/assets/develop/getting-started/launch-profiles.png" alt="Launch Profiles" loading="lazy"></p><h2 id="gradle-tasks" tabindex="-1">Gradle Tasks <a class="header-anchor" href="#gradle-tasks" aria-label="Permalink to “Gradle Tasks”">​</a></h2><p>If you&#39;re using the command line, you can use the following Gradle commands to start the game:</p><ul><li><code>./gradlew runClient</code> - Start the game in client mode.</li><li><code>./gradlew runServer</code> - Start the game in server mode.</li></ul><p>The only problem with this approach is that you can&#39;t easily debug your code. If you want to debug your code, you&#39;ll need to use the launch profiles in IntelliJ IDEA or via your IDE&#39;s Gradle integration.</p><h2 id="hotswapping-classes" tabindex="-1">Hotswapping Classes <a class="header-anchor" href="#hotswapping-classes" aria-label="Permalink to “Hotswapping Classes”">​</a></h2><p>When you run the game in debug mode, you can hotswap your classes without restarting the game. This is useful for quickly testing changes to your code.</p><p>You&#39;re still quite limited though:</p><ul><li>You can&#39;t add or remove methods</li><li>You can&#39;t change method parameters</li><li>You can&#39;t add or remove fields</li></ul><p>However, by using the <a href="https://github.com/JetBrains/JetBrainsRuntime" target="_blank" rel="noreferrer">JetBrains Runtime</a>, you are able to circumvent most of the limitations, and even add or remove classes and methods. This should allow most changes to take effect without restarting the game.</p><p>Don&#39;t forget to add the following to the VM Arguments option in your Minecraft run configuration:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>-XX:+AllowEnhancedClassRedefinition</span></span></code></pre></div><h2 id="hotswapping-mixins" tabindex="-1">Hotswapping Mixins <a class="header-anchor" href="#hotswapping-mixins" aria-label="Permalink to “Hotswapping Mixins”">​</a></h2><p>If you&#39;re using Mixins, you can hotswap your Mixin classes without restarting the game. This is useful for quickly testing changes to your Mixins.</p><p>You will need to install the Mixin Java agent for this to work though.</p><h3 id="1-locate-the-mixin-library-jar" tabindex="-1">1. Locate the Mixin Library Jar <a class="header-anchor" href="#1-locate-the-mixin-library-jar" aria-label="Permalink to “1. Locate the Mixin Library Jar”">​</a></h3><p>In IntelliJ IDEA, you can find the mixin library jar in the &quot;External Libraries&quot; section of the &quot;Project&quot; section:</p><p><img src="/assets/develop/getting-started/mixin-library.png" alt="Mixin Library" loading="lazy"></p><p>You will need to copy the jar&#39;s &quot;Absolute Path&quot; for the next step.</p><h3 id="2-add-the--javaagent-vm-argument" tabindex="-1">2. Add the <code>-javaagent</code> VM Argument <a class="header-anchor" href="#2-add-the--javaagent-vm-argument" aria-label="Permalink to “2. Add the -javaagent VM Argument”">​</a></h3><p>In your &quot;Minecraft Client&quot; and or &quot;Minecraft Server&quot; run configuration, add the following to the VM Arguments option:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>-javaagent:&quot;path to mixin library jar here&quot;</span></span></code></pre></div><p><img src="/assets/develop/getting-started/vm-arguments.png" alt="VM Arguments Screenshot" loading="lazy"></p><p>Now, you should be able to modify the contents of your mixin methods during debugging and have the changes take effect without restarting the game.</p>`,29)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};